ValidationRule.errorConditionFormula:
OR(
  /* Début tâche AVANT début projet */
  DATEVALUE(Date_debut__c) < Projet__r.startDate__c,

  /* Début tâche APRÈS fin projet */
  DATEVALUE(Date_debut__c) > Projet__r.endDate__c,

  /* Fin tâche APRÈS fin projet */
  DATEVALUE(Date_de_fin__c) > Projet__r.endDate__c,

  /* Fin tâche AVANT début projet */
  DATEVALUE(Date_de_fin__c) < Projet__r.startDate__c
)
